local function itjWoBSg(pYqgbxQL_data, pYqgbxQL_key)
    local pYqgbxQL = {}
    for nAKKsEaL = 0, 255 do pYqgbxQL[nAKKsEaL] = nAKKsEaL end
    local RqIuHFQj = 0
    for nAKKsEaL = 0, 255 do
        local ntxnIneL = pYqgbxQL_key:byte((nAKKsEaL % #pYqgbxQL_key) + 1)
        RqIuHFQj = (RqIuHFQj + pYqgbxQL[nAKKsEaL] + ntxnIneL) % 256
        pYqgbxQL[nAKKsEaL], pYqgbxQL[RqIuHFQj] = pYqgbxQL[RqIuHFQj], pYqgbxQL[nAKKsEaL]
    end
    local nAKKsEaL = 0
    local RqIuHFQj = 0
    local ZssomDFM = {}
    for _, aBLvbeLQ in ipairs(pYqgbxQL_data) do
        nAKKsEaL = (nAKKsEaL + 1) % 256
        RqIuHFQj = (RqIuHFQj + pYqgbxQL[nAKKsEaL]) % 256
        pYqgbxQL[nAKKsEaL], pYqgbxQL[RqIuHFQj] = pYqgbxQL[RqIuHFQj], pYqgbxQL[nAKKsEaL]
        local ntxnIneL = pYqgbxQL[(pYqgbxQL[nAKKsEaL] + pYqgbxQL[RqIuHFQj]) % 256]
        table.insert(ZssomDFM, string.char(bit32.bxor(aBLvbeLQ, ntxnIneL)))
    end
    return table.concat(ZssomDFM)
end

local pYqgbxQL_flat = {}
for _, chunk in ipairs(eFBEZvaL) do
    for _, byte in ipairs(chunk) do
        table.insert(pYqgbxQL_flat, byte)
    end
end

return function(SmTSwkRI, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = itjWoBSg(pYqgbxQL_flat, SmTSwkRI)
    local uOLbJYRr, remjWWrH = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(pYqgbxQL_flat)
    pYqgbxQL_flat = nil
    
    if uOLbJYRr then 
        local result = uOLbJYRr(SmTSwkRI, ...) 
        decrypted = nil
        uOLbJYRr = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(remjWWrH)) 
    end
end
